import{_ as a,o,c as t,ae as s}from"./chunks/framework.B6gjLfeO.js";const m=JSON.parse('{"title":"Google Ads FAQ","description":"","frontmatter":{"title":"Google Ads FAQ","slug":"google-ads-faq"},"headers":[],"relativePath":"marketer-hub/google-ads-faq.md","filePath":"marketer-hub/google-ads-faq.md"}'),r={name:"marketer-hub/google-ads-faq.md"};function n(i,e,d,l,h,c){return o(),t("div",null,[...e[0]||(e[0]=[s('<p>The most frequently asked questions about Google Ads.</p><details><summary>Why am I unable to see Google Ad Set and Ad Set ID in Analytics?</summary><p>The ad dimensions, for example, ad name and ad set name are not supported for the Google AdWords UAC campaigns.</p><p>This is since Ad Set Name is not among the supported variables passed to Branch via Google AdWords for such campaigns. You can only see the ad group ID for non-UAC campaigns on conversions.</p><p>Branch doc - <a href="./common-sources-of-san-reporting-discrepancies.html#available-reporting-filters">Common Sources of SAN Reporting Discrepancies</a></p></details><details><summary>Why do Google Ads get disapproved destination mismatch using Branch Links?</summary><p>Google has a destination mismatch policy, which indicates that the final url should not have any redirect when a user click on a Google ad. You can refer to a Google doc here: <a href="https://support.google.com/adspolicy/answer/6368661?hl=en" target="_blank" rel="noreferrer">https://support.google.com/adspolicy/answer/6368661?hl=en</a></p><p>While Branch Links will always redirect user before taking them to the destination, they get disapproved if used in the final URL section of their ads, hence it is recommended to use the Branch Link in the tracking template URL instead which allows for parallel tracking and does not break attribution for web based campaigns.</p><p>More on parallel tracking and general FAQ related to Google ads can be found here: <a href="./google-ads.html#general-faqs">Google Ads</a></p></details><details><summary>Will adding custom parameter ~customer\\_ad\\_set\\_name or ~customer\\_ad\\_name to the Branch Ad Link result in including the ad group name in Branch Dashboard?</summary><p>For data coming through our SAN connector, this is a limitation based on what Google provides--you can find the full mapping <a href="./google-ads-data-reporting.html">here</a>, but Branch only showing ‘ad set id’ is due to Google only providing the ‘ad set id’ to us for this value. For this SAN-based data, there’s no way to tweak what reporting labels are being used.</p><p>However, for any activity that is coming through Branch Links instead of using the SAN connector (as some search traffic maybe), you can also opt to use ‘~ad_set_name’ rather than a ‘~customer_x value’. If ‘~ad_set_name’ is not already in use by your team, there would be no conflict presented from this solution, and it would keep your data values more closely paired with the ~ad_set_id value Branch is already getting.</p></details>',4)])])}const g=a(r,[["render",n]]);export{m as __pageData,g as default};
